import "./Recruitment.css";
import { useNavigate } from "react-router-dom";

function Recruitment() {
  const navigate = useNavigate();

  return (
    <div className="recruitment-container">
      <h2>Recruitment Module</h2>

      <div className="recruitment-buttons">
        <button onClick={() => navigate("/dashboard/recruitment/designations")}>
          Generate Employee Designation
        </button>

        <button onClick={() => navigate("/dashboard/recruitment/view-by-role")}>
          View Employees By Designation
        </button>

        <button onClick={() => navigate("/dashboard/recruitment/create-login")}>
          Create Login Credentials
        </button>

        {/* NEW INTERNAL JOB PORTAL */}
        <button onClick={() => navigate("/dashboard/recruitment/internal-portal")}>
          Internal Job Portal
        </button>
        <button
 className="recruit-btn"
 onClick={() => navigate("/dashboard/view-applicants")}
>
  View Job Applications
</button>

      </div>
    </div>
  );
}

export default Recruitment;
